if (!items || items.length === 0) return [];

const first = items[0].json;

// HTTP Request may return the array as one item OR already split into individual items
if (Array.isArray(first)) {
  return first.map(listing => ({ json: listing }));
}

// Already split — pass through, filter out anything without an id
return items.filter(item => item.json && item.json.id);

const listings = $('Has Results?').all();

return items.map((item, index) => {
  const original = listings[index]?.json || {};

  try {
    const rawString = item.json.text || item.json.output;
    const cleanString = rawString.replace(/```json|```/g, '').trim();
    const aiData = JSON.parse(cleanString);

    const bullets = (aiData.highlights || []).map(h => `• ${h}`).join('\n');

    const d = { ...original, ...aiData };
    const price = d.warm_rent || d.cold_rent || '?';
    const loc = [d.city, d.zip_code, d.district].filter(Boolean).join(' ');

    d.tg_message = [
      `🏠 <b>${d.title || ''}</b>`,
      `📍 ${loc}`,
      '',
      `💶 ${price} € warm`,
      `🚪 ${d.rooms || '?'} rooms  |  📐 ${d.living_space || '?'} m²`,
      `⭐ <b>Score: ${d.score}/10</b>`,
      '',
      bullets,
      '',
      `🔗 <a href="${d.url}">View listing (${d.portal})</a>`,
    ].join('\n');

    return { json: d };
  } catch (error) {
    return { json: { ...original, is_relevant: false, score: 0, reject_reason: 'AI parse error', tg_message: 'Error' } };
  }
});
